import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.DSLFjWWy.js";const u=JSON.parse('{"title":"Comparison and Tradeoffs","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/comparison-and-tradeoffs.md","filePath":"concepts/comparison-and-tradeoffs.md","lastUpdated":1781454385000}'),n={name:"concepts/comparison-and-tradeoffs.md"};function r(s,e,d,l,c,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="comparison-and-tradeoffs" tabindex="-1">Comparison and Tradeoffs <a class="header-anchor" href="#comparison-and-tradeoffs" aria-label="Permalink to &quot;Comparison and Tradeoffs&quot;">​</a></h1><p>AOSC is one option for index migration. It is not a replacement for every OpenSearch migration mechanism.</p><h2 id="comparison" tabindex="-1">Comparison <a class="header-anchor" href="#comparison" aria-label="Permalink to &quot;Comparison&quot;">​</a></h2><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Need</th><th>Common Option</th><th>Notes</th></tr></thead><tbody><tr><td>Add a compatible mapping field</td><td>OpenSearch mapping update</td><td>Often no migration is needed.</td></tr><tr><td>Copy a small or offline index</td><td><code>_reindex</code></td><td>Simpler operationally when write reconciliation is not needed.</td></tr><tr><td>Change shard count only</td><td>Split/shrink where applicable</td><td>Native operations may be better when their constraints fit.</td></tr><tr><td>Transform documents in the same cluster while source stays live</td><td>AOSC or custom pipeline</td><td>AOSC handles backfill, replay, and alias cutover.</td></tr><tr><td>Cross-cluster movement</td><td>Remote reindex, snapshot/restore, CCR, or custom replication</td><td>AOSC is same-cluster only.</td></tr></tbody></table></div><h2 id="aosc-vs-reindex" tabindex="-1">AOSC vs <code>_reindex</code> <a class="header-anchor" href="#aosc-vs-reindex" aria-label="Permalink to &quot;AOSC vs `_reindex`&quot;">​</a></h2><p><code>_reindex</code> is simpler and well-known. It is a good default when the source can be made quiet or when you have a separate reconciliation path for writes that occur during reindex.</p><p>AOSC adds operation-history replay and coordinated cutover for live same-cluster migrations, at the cost of installing a plugin and accepting AOSC&#39;s routing, transform, and cutover constraints.</p><h2 id="aosc-vs-split-shrink" tabindex="-1">AOSC vs Split/Shrink <a class="header-anchor" href="#aosc-vs-split-shrink" aria-label="Permalink to &quot;AOSC vs Split/Shrink&quot;">​</a></h2><p>Split and shrink are native operations for specific shard-count changes. They have their own constraints and do not solve document reshaping. Use them when the change fits the native operation and you do not need AOSC&#39;s replay workflow.</p><h2 id="aosc-vs-manual-reindex-and-alias-swap" tabindex="-1">AOSC vs Manual Reindex and Alias Swap <a class="header-anchor" href="#aosc-vs-manual-reindex-and-alias-swap" aria-label="Permalink to &quot;AOSC vs Manual Reindex and Alias Swap&quot;">​</a></h2><p>A manual workflow gives you full control but requires you to design backfill, replay/reconciliation, validation, retry behavior, and rollback. AOSC packages those steps into the plugin, but only for supported same-cluster use cases.</p><h2 id="when-aosc-is-a-reasonable-fit" tabindex="-1">When AOSC Is a Reasonable Fit <a class="header-anchor" href="#when-aosc-is-a-reasonable-fit" aria-label="Permalink to &quot;When AOSC Is a Reasonable Fit&quot;">​</a></h2><ul><li>The source must continue receiving writes during most of the migration.</li><li>The target index needs different mappings, settings, shard count, or transformed source documents.</li><li>The application writes through an alias and retries write-block rejections.</li><li>The migration is same-cluster.</li><li>You can test the transform and routing behavior before migration.</li></ul><h2 id="when-to-avoid-aosc" tabindex="-1">When to Avoid AOSC <a class="header-anchor" href="#when-to-avoid-aosc" aria-label="Permalink to &quot;When to Avoid AOSC&quot;">​</a></h2><ul><li>The source can be stopped and <code>_reindex</code> is enough.</li><li>The migration is cross-cluster.</li><li>Alias-based cutover is not possible.</li><li>Custom routing plus shard changes cannot be validated safely.</li><li>You need a full dry-run mode or formal metrics export.</li></ul>',15)])])}const m=a(n,[["render",r]]);export{u as __pageData,m as default};
